using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class AiTraining : TrainingContentBase
{
    public AiTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "AI Assistant Overview",
            Slug = "ai-overview",
            Summary = "What the AI Assistant feature does, how conversations work, and how to get the most out of domain-specific assistants.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/ai"]""",
            Tags = """["ai","assistant","chat"]""",
            ContentJson = """{"body":"## AI Assistant Overview\n\nThe AI Assistant feature gives you access to domain-specific AI assistants that can answer questions, draft content, and help with day-to-day tasks. Each assistant is trained for a specific area — HR, Procurement, Sales, or general engineering — so the answers you get are relevant to your work.\n\n### How It Works\n\nThe AI page uses a two-panel layout:\n- **Sidebar (left):** A list of assistant cards showing each assistant's icon, name, description, and an active indicator for the one you're currently chatting with.\n- **Chat area (right):** Where the conversation happens. When you first select an assistant, you'll see a welcome screen with the assistant's icon, name, description, and a grid of starter questions to help you get going.\n\n### Starting a Conversation\n\nClick any assistant card in the sidebar to select it. If you haven't chatted with that assistant yet, you'll see the welcome screen with starter questions. Click a starter question or type your own in the message input at the bottom.\n\n### Message Input\n\n- Type your question in the text field (placeholder shows 'Ask {assistantName}')\n- Press **Enter** to send, **Shift+Enter** to add a new line\n- The **Send** button (send icon) is disabled when the input is empty or a response is being generated\n- The **Clear Chat** button (delete_sweep icon) clears the current conversation and returns to the welcome screen — it's disabled when there are no messages\n\n### How Context Works\n\nThe assistant sees the last 10 messages of your conversation as context, so it can follow up on previous questions. Conversations are maintained per-assistant in memory — switching to a different assistant and back will keep your chat history for the current session. However, conversations are not persisted between sessions (closing the browser clears them).\n\n### Assistant Responses\n\nAssistant messages appear with an avatar and icon. While the assistant is thinking, you'll see a typing indicator (three animated dots). Responses may include formatted text, lists, and code snippets depending on the question.\n\n### When to Use the AI Assistant\n\n- When you need a quick answer about a process or policy\n- When drafting job descriptions, emails, or documentation\n- When you want to search across uploaded documents (RAG-powered)\n- When exploring what-if scenarios for procurement or sales\n- When you need help interpreting QC data or production metrics","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "AI Assistant — Guided Tour",
            Slug = "ai-walkthrough",
            Summary = "A guided tour of the AI Assistant page: selecting assistants, starting conversations, using starter questions, and managing chat history.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/ai"]""",
            Tags = """["ai","walkthrough"]""",
            ContentJson = """{"appRoute":"/ai","startButtonLabel":"Tour AI Assistant","steps":[{"element":".ai-sidebar","popover":{"title":"Assistant Sidebar","description":"This sidebar lists all available AI assistants. Each card shows the assistant's icon, name, and a short description. The currently active assistant is highlighted with an active indicator. Click any card to switch assistants.","side":"right"}},{"element":".ai-chat__welcome","popover":{"title":"Welcome Screen","description":"When you select an assistant, this welcome area shows the assistant's icon, name, and description. Below that is a grid of starter questions — click any one to begin a conversation on that topic.","side":"left"}},{"element":".ai-chat__starters","popover":{"title":"Starter Questions","description":"These pre-configured questions help you get started quickly. Each assistant has its own set of relevant starter questions. Click one to send it as your first message.","side":"top"}},{"element":".ai-chat__text-input","popover":{"title":"Message Input","description":"Type your question here. Press Enter to send or Shift+Enter for a new line. The placeholder shows 'Ask {assistantName}' to remind you which assistant you're talking to.","side":"top"}},{"element":".ai-chat__send","popover":{"title":"Send Message","description":"Click to send your message (or just press Enter). The button is disabled when the input is empty or while the assistant is generating a response. Look for the typing indicator (three animated dots) while waiting.","side":"bottom"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "AI Assistant Field Reference",
            Slug = "ai-field-reference",
            Summary = "Complete reference for every element, button, indicator, and behavior in the AI Assistant feature.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/ai"]""",
            Tags = """["ai","reference"]""",
            ContentJson = """{"title":"AI Assistant Field Reference","groups":[{"heading":"Sidebar Elements","items":[{"label":"Assistant Card","value":"Displays icon, name, and description for each assistant. Click to select. The active assistant is highlighted with a visual indicator."},{"label":"Icon","value":"Material icon representing the assistant's domain (e.g., school for HR, shopping_cart for Procurement). Configured by admin."},{"label":"Name","value":"The assistant's display name (e.g., 'HR Assistant', 'Sales Advisor'). Set by admin in AI Assistants settings."},{"label":"Description","value":"Short summary of what the assistant specializes in. Shown on the card and in the welcome screen."},{"label":"Active Indicator","value":"Visual highlight on the currently selected assistant card. Only one assistant is active at a time."}]},{"heading":"Chat Area — Welcome Screen","items":[{"label":"Assistant Icon (large)","value":"Prominent display of the selected assistant's icon, shown centered above the name."},{"label":"Assistant Name","value":"Large heading showing which assistant you're chatting with."},{"label":"Assistant Description","value":"Full description of the assistant's capabilities and focus area."},{"label":"Starter Questions Grid","value":"Grid of clickable question cards. Each assistant has its own set of starter questions configured by admin. Clicking one sends it as the first message."}]},{"heading":"Chat Area — Message Thread","items":[{"label":"User Messages","value":"Right-aligned bubbles showing your sent messages. Displayed with your initials/avatar."},{"label":"Assistant Messages","value":"Left-aligned bubbles with the assistant's avatar and icon. May contain formatted text, lists, and code blocks."},{"label":"Typing Indicator","value":"Three animated dots shown while the assistant is generating a response. Appears in the assistant's message area."},{"label":"Message History","value":"Scrollable thread of all messages in the current conversation. Last 10 messages are sent as context to the API for each new question."}]},{"heading":"Buttons and Actions","items":[{"label":"Send (send icon)","value":"Sends the current message to the assistant. Disabled when input is empty or while a response is being generated. Keyboard shortcut: Enter."},{"label":"Clear Chat (delete_sweep icon)","value":"Clears all messages for the current assistant and returns to the welcome screen. Disabled when there are no messages. Does not affect other assistants' conversations."},{"label":"Starter Question (card click)","value":"Sends the selected starter question as your first message, beginning the conversation."},{"label":"Assistant Card (sidebar click)","value":"Switches to the selected assistant. Your previous conversation with each assistant is preserved in memory for the session."}]},{"heading":"Input Behavior","items":[{"label":"Text Input","value":"Multi-line text field. Placeholder: 'Ask {assistantName}' where {assistantName} is the current assistant's name."},{"label":"Enter","value":"Sends the message (equivalent to clicking Send)."},{"label":"Shift+Enter","value":"Inserts a new line without sending. Use for multi-line questions."},{"label":"Empty Input","value":"Send button is disabled. You cannot send an empty message."},{"label":"While Sending","value":"Send button is disabled and shows a loading state until the assistant responds."}]},{"heading":"Data and API","items":[{"label":"Assistant List","value":"Loaded from GET /api/v1/ai/assistants. Returns AiAssistantListItem objects with id, name, description, icon, color, category, starterQuestions, and isActive flag."},{"label":"Chat Request","value":"POST /api/v1/ai/assistants/{id}/chat with body {text, history[]}. History includes the last 10 messages for context."},{"label":"Conversation Storage","value":"In-memory only (not persisted). Each assistant has its own conversation. Closing the browser or refreshing the page clears all conversations."},{"label":"Route","value":"/ai/{assistantId} — the selected assistant ID is in the URL, making it shareable/bookmarkable."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "AI Assistant Knowledge Check",
            Slug = "ai-quiz",
            Summary = "Test your knowledge of the AI Assistant feature: navigation, conversations, context, and assistant management.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/training"]""",
            Tags = """["ai","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"ai1","text":"You want to ask the HR Assistant about the company's PTO policy. How do you start?","options":[{"id":"a","text":"Go to Admin → AI Settings and type your question in the configuration panel"},{"id":"b","text":"Navigate to the AI page, click the HR Assistant card in the sidebar, then type your question or click a starter question","isCorrect":true},{"id":"c","text":"Open the Chat feature and create a new room called 'HR Questions'"},{"id":"d","text":"Go to Training → search for PTO policy in the module list"}],"explanation":"Navigate to the AI page (/ai), select the HR Assistant from the sidebar, and either type your question in the input or click one of the starter questions on the welcome screen."},{"id":"ai2","text":"You're chatting with the Sales Advisor and want to start a new line in your message without sending it. What key combination do you use?","options":[{"id":"a","text":"Ctrl+Enter"},{"id":"b","text":"Alt+Enter"},{"id":"c","text":"Shift+Enter","isCorrect":true},{"id":"d","text":"Tab then Enter"}],"explanation":"Shift+Enter inserts a new line in the message input. Pressing Enter alone sends the message."},{"id":"ai3","text":"How many of your previous messages does the AI assistant use as context when generating a response?","options":[{"id":"a","text":"All messages from the entire conversation"},{"id":"b","text":"The last 10 messages","isCorrect":true},{"id":"c","text":"Only your most recent message — no history"},{"id":"d","text":"The last 50 messages or 4000 tokens, whichever is smaller"}],"explanation":"The API sends the last 10 messages as the history array in the chat request. This gives the assistant enough context to follow up on recent topics without sending excessive data."},{"id":"ai4","text":"You switch from the Procurement Assistant to the HR Assistant and then back to Procurement. What happens to your Procurement conversation?","options":[{"id":"a","text":"It's gone — switching assistants clears all conversations"},{"id":"b","text":"It's preserved in memory for the current session","isCorrect":true},{"id":"c","text":"It's saved to the database and can be resumed anytime"},{"id":"d","text":"Only the last 3 messages are kept; older ones are discarded"}],"explanation":"Conversations are maintained per-assistant in memory. Switching assistants doesn't clear anything — each assistant keeps its own conversation. However, conversations are not persisted, so closing the browser clears them."},{"id":"ai5","text":"The Clear Chat button (delete_sweep icon) is grayed out. Why?","options":[{"id":"a","text":"You don't have permission to clear chats"},{"id":"b","text":"The assistant is currently generating a response"},{"id":"c","text":"There are no messages in the current conversation — nothing to clear","isCorrect":true},{"id":"d","text":"Clear Chat is only available to Admin and Manager roles"}],"explanation":"The Clear Chat button is disabled when there are no messages. Once you send at least one message, the button becomes active."},{"id":"ai6","text":"What do the three animated dots in the chat area indicate?","options":[{"id":"a","text":"The assistant is offline and cannot respond"},{"id":"b","text":"Your message failed to send and is being retried"},{"id":"c","text":"The assistant is generating a response — a typing indicator","isCorrect":true},{"id":"d","text":"The system is loading the assistant's configuration"}],"explanation":"The typing indicator (three animated dots) appears while the assistant is processing your question and generating a response. The Send button is also disabled during this time."},{"id":"ai7","text":"You refresh the browser while chatting with an assistant. What happens to your conversation?","options":[{"id":"a","text":"It's fully restored from the server"},{"id":"b","text":"It's restored from localStorage"},{"id":"c","text":"It's cleared — conversations are in-memory only and not persisted","isCorrect":true},{"id":"d","text":"Only the last message is preserved via the URL query string"}],"explanation":"Conversations are stored in memory only. Refreshing the page, closing the tab, or navigating away clears all conversations. This is by design — the AI feature is for quick interactions, not long-term record-keeping."},{"id":"ai8","text":"Where do starter questions come from for each assistant?","options":[{"id":"a","text":"They're hardcoded in the frontend based on the assistant category"},{"id":"b","text":"They're configured by an admin in the AI Assistants admin panel and loaded from the API","isCorrect":true},{"id":"c","text":"The AI generates them dynamically based on your role and recent activity"},{"id":"d","text":"They're pulled from the Training module's quiz questions"}],"explanation":"Starter questions are part of each assistant's configuration (the starterQuestions field on AiAssistantListItem). Admins configure them in Admin → AI Assistants. They're loaded from GET /api/v1/ai/assistants."},{"id":"ai9","text":"You want to share a link to the Procurement Assistant with a coworker. Is this possible?","options":[{"id":"a","text":"No — the AI page doesn't support direct linking to specific assistants"},{"id":"b","text":"Yes — the assistant ID is in the URL (/ai/{assistantId}), so you can copy and share the link","isCorrect":true},{"id":"c","text":"Yes, but only if you export the conversation first"},{"id":"d","text":"No — they need to navigate to the AI page and select the assistant manually"}],"explanation":"The route is /ai/{assistantId}, so the selected assistant is reflected in the URL. Your coworker can use the link to go directly to that assistant's page. However, they won't see your conversation — only the welcome screen."},{"id":"ai10","text":"The Send button is disabled even though you've typed a message. What's the most likely reason?","options":[{"id":"a","text":"The assistant is currently generating a response to your previous message","isCorrect":true},{"id":"b","text":"Your message exceeds the maximum character limit"},{"id":"c","text":"The assistant has been deactivated by an admin"},{"id":"d","text":"You need to select an assistant first before sending"}],"explanation":"The Send button is disabled in two cases: when the input is empty, or when the assistant is currently generating a response (sending state). Since you've typed a message, the most likely reason is that a response is still being generated."},{"id":"ai11","text":"What information does each assistant card in the sidebar display?","options":[{"id":"a","text":"Name only — you have to click to see details"},{"id":"b","text":"Icon, name, description, and an active indicator for the selected assistant","isCorrect":true},{"id":"c","text":"Name, last message preview, and timestamp of last conversation"},{"id":"d","text":"Name, category, number of conversations, and a star rating"}],"explanation":"Each sidebar card shows the assistant's icon (Material icon), name, description, and an active indicator highlighting which assistant is currently selected."},{"id":"ai12","text":"An admin wants to add a new AI assistant for the Quality department. Where do they configure it?","options":[{"id":"a","text":"In the AI page itself — click 'New Assistant' in the sidebar"},{"id":"b","text":"In Admin → AI Assistants — create a new assistant with name, description, icon, color, category, and starter questions","isCorrect":true},{"id":"c","text":"By editing the assistant configuration JSON file and restarting the server"},{"id":"d","text":"In Admin → System Settings under the AI section"}],"explanation":"AI assistants are managed in the Admin → AI Assistants panel. Admins can create, edit, and deactivate assistants there. The assistant list is loaded from the API (GET /api/v1/ai/assistants), so changes are reflected immediately."}]}"""
        });

        Log.Information("Seeded AI Assistant training modules");
    }
}
